+/// Find a keyword (like ` in ` or ` of `) at the top level of an expression,
+/// respecting parentheses, brackets, braces, and quotes.
+fn find_top_level_keyword(src: &str, keyword: &str) -> Option<usize> {
+    let bytes = src.as_bytes();
+    let kw_bytes = keyword.as_bytes();
+    let kw_len = kw_bytes.len();
+    if bytes.len() < kw_len {
+        return None;
+    }
+    let mut depth_paren = 0i32;
+    let mut depth_bracket = 0i32;
+    let mut depth_brace = 0i32;
+    let mut in_single = false;
+    let mut in_double = false;
+    let mut in_backtick = false;
+    let mut i = 0;
+    while i < bytes.len() {
+        let b = bytes[i];
+        if in_single {
+            if b == b'\\' {
+                i += 1;
+            } else if b == b'\'' {
+                in_single = false;
+            }
+        } else if in_double {
+            if b == b'\\' {
+                i += 1;
+            } else if b == b'"' {
+                in_double = false;
+            }
+        } else if in_backtick {
+            if b == b'\\' {
+                i += 1;
+            } else if b == b'`' {
+                in_backtick = false;
+            }
+        } else {
+            match b {
+                b'\'' => in_single = true,
+                b'"' => in_double = true,
+                b'`' => in_backtick = true,
+                b'(' => depth_paren += 1,
+                b')' => depth_paren -= 1,
+                b'[' => depth_bracket += 1,
+                b']' => depth_bracket -= 1,
+                b'{' => depth_brace += 1,
+                b'}' => depth_brace -= 1,
+                _ => {}
+            }
+            if depth_paren == 0
+                && depth_bracket == 0
+                && depth_brace == 0
+                && i + kw_len <= bytes.len()
+                && &bytes[i..i + kw_len] == kw_bytes
+            {
+                return Some(i);
+            }
+        }
+        i += 1;
+    }
+    None
+}
